   "rank": 21,
   "name": "TIE/ln Fighter",
   "craft": "Sienar Fleet Systems TIE/ln",
   "type": "Space Superiority Fighter",
   "affiliation": "Empire",
   "era": "Rise of the Empire",
   "source": "Core Rulebook (pages 249-250)",
